lines = []
# AuditPlanTab
lines.append('')
lines.append('// ─── AUDIT PLAN TAB (MP-09) ──────────────────────────────────────────────────')
lines.append('function AuditPlanTab({ auditPlans, setAuditPlans }) {')
lines.append('  const [modal, setModal] = useState(null);')
lines.append('  const [filter, setFilter] = useState("all");')
lines.append('  const statusColor = s => s==="\u5df2\u5b8c\u6210"?"#22c55e":s==="\u8a08\u756b\u4e2d"?"#60a5fa":s==="\u9032\u884c\u4e2d"?"#f97316":"#ef4444";')
lines.append('  const filtered = filter==="all" ? auditPlans : auditPlans.filter(a=>a.status===filter);')
lines.append('  const upcoming = auditPlans.filter(a=>a.status==="\u8a08\u756b\u4e2d" && daysUntil(a.scheduledDate)<=30 && daysUntil(a.scheduledDate)>=0);')
lines.append('  function markComplete(id) {')
lines.append('    setAuditPlans(prev => prev.map(a => a.id===id ? {...a, status:"\u5df2\u5b8c\u6210", actualDate: new Date().toISOString().split("T")[0]} : a));')
lines.append('    setModal(null);')
lines.append('  }')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <SectionHeader title="\u5167\u90e8\u7a3d\u6838\u8a08\u756b\u7ba1\u7406\uff08MP-09\uff09" count={auditPlans.length} color="#8b5cf6" />')
lines.append('      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>')
lines.append('        <StatCard label="\u5e74\u5ea6\u8a08\u756b\u7e3d\u6578" value={auditPlans.length} color="#8b5cf6" />')
lines.append('        <StatCard label="\u5df2\u5b8c\u6210" value={auditPlans.filter(a=>a.status==="\u5df2\u5b8c\u6210").length} color="#22c55e" />')
lines.append('        <StatCard label="\u8a08\u756b\u4e2d" value={auditPlans.filter(a=>a.status==="\u8a08\u756b\u4e2d").length} color="#60a5fa" />')
lines.append('        <StatCard label="30\u5929\u5167\u5373\u5c07\u57f7\u884c" value={upcoming.length} color="#f97316" sub="\u9700\u4e8b\u5148\u6e96\u5099" />')
lines.append('      </div>')
lines.append('      {upcoming.length>0 && (')
lines.append('        <div style={{ background: "rgba(249,115,22,0.08)", border: "1px solid rgba(249,115,22,0.2)", borderRadius: 12, padding: 16, marginBottom: 20 }}>')
lines.append('          <div style={{ fontSize: 13, color: "#fb923c", fontWeight: 700, marginBottom: 10 }}>\u26a0 30\u5929\u5167\u5373\u5c07\u57f7\u884c\u7684\u7a3d\u6838</div>')
lines.append('          {upcoming.map(a => (<div key={a.id} style={{ display:"flex", gap:12, alignItems:"center", marginBottom:6 }}><span style={{ color:"#60a5fa", fontFamily:"monospace", fontSize:12 }}>{a.id}</span><span style={{ color:"#e2e8f0", fontSize:13 }}>{a.dept} \u2014 {formatDate(a.scheduledDate)}</span><Badge color="#f97316">\u5269{daysUntil(a.scheduledDate)}\u5929</Badge></div>))}')
lines.append('        </div>')
lines.append('      )}')
lines.append('      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>')
lines.append('        {["all","\u5df2\u5b8c\u6210","\u8a08\u756b\u4e2d","\u9032\u884c\u4e2d"].map(f => (<button key={f} onClick={()=>setFilter(f)} style={{ background:filter===f?"rgba(139,92,246,0.2)":"rgba(255,255,255,0.04)", border:`1px solid ${filter===f?"rgba(139,92,246,0.5)":"rgba(255,255,255,0.1)"}`, borderRadius:8, color:filter===f?"#c4b5fd":"#64748b", cursor:"pointer", padding:"6px 14px", fontSize:12, fontWeight:600 }}>{f==="all"?"\u5168\u90e8":f}</button>))}')
lines.append('      </div>')
lines.append('      <div style={{ overflowX: "auto" }}>')
lines.append('        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>')
lines.append('          <thead><tr>{["\u7a3d\u6838\u7de8\u865f","\u5e74\u5ea6","\u671f\u9593","\u9810\u5b9a\u65e5\u671f","\u7a3d\u6838\u90e8\u9580","\u5c0d\u8c61","\u7a3d\u6838\u54e1","\u7a3d\u6838\u7bc4\u570d","\u72c0\u614b","\u767c\u73fe\u6578","NC\u6578",""].map(h => (<th key={h} style={{ textAlign:"left", padding:"10px 12px", color:"#64748b", fontWeight:600, borderBottom:"1px solid rgba(255,255,255,0.06)", whiteSpace:"nowrap" }}>{h}</th>))}</tr></thead>')
lines.append('          <tbody>')
lines.append('            {filtered.map((a,i) => (')
lines.append('              <tr key={a.id} style={{ background:i%2===0?"rgba(255,255,255,0.02)":"transparent" }}>')
lines.append('                <td style={{ padding:"10px 12px", color:"#8b5cf6", fontWeight:700, fontFamily:"monospace", whiteSpace:"nowrap" }}>{a.id}</td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#94a3b8" }}>{a.year}</td>')
lines.append('                <td style={{ padding:"10px 12px" }}><Badge color={a.period==="\u4e0a\u534a\u5e74"?"#60a5fa":"#f97316"}>{a.period}</Badge></td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#94a3b8", whiteSpace:"nowrap" }}>{formatDate(a.scheduledDate)}</td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#e2e8f0", fontWeight:600 }}>{a.dept}</td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#94a3b8" }}>{a.auditee}</td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#94a3b8" }}>{a.auditor}</td>')
lines.append('                <td style={{ padding:"10px 12px", color:"#64748b", fontSize:11 }}>{a.scope}</td>')
lines.append('                <td style={{ padding:"10px 12px" }}><Badge color={statusColor(a.status)}>{a.status}</Badge></td>')
lines.append('                <td style={{ padding:"10px 12px", textAlign:"center", color:a.findings>0?"#f97316":"#94a3b8", fontWeight:700 }}>{a.findings}</td>')
lines.append('                <td style={{ padding:"10px 12px", textAlign:"center", color:a.ncCount>0?"#ef4444":"#94a3b8", fontWeight:700 }}>{a.ncCount}</td>')
lines.append('                <td style={{ padding:"10px 12px" }}><button onClick={()=>setModal(a)} style={{ background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.1)", borderRadius:6, color:"#94a3b8", cursor:"pointer", padding:"4px 10px", fontSize:11 }}>\u8a73\u60c5</button></td>')
lines.append('              </tr>')
lines.append('            ))}')
lines.append('          </tbody>')
lines.append('        </table>')
lines.append('      </div>')
lines.append('      {modal && (<Modal title={`\u7a3d\u6838\u8a73\u60c5\uff1a${modal.id}`} onClose={() => setModal(null)}><div style={{ display:"flex", flexDirection:"column", gap:14 }}>{[["\u7a3d\u6838\u7de8\u865f",modal.id],["\u7a3d\u6838\u90e8\u9580",modal.dept],["\u9810\u5b9a\u65e5\u671f",formatDate(modal.scheduledDate)],["\u5be6\u969b\u65e5\u671f",formatDate(modal.actualDate)],["\u7a3d\u6838\u54e1",modal.auditor],["\u7a3d\u6838\u5c0d\u8c61",modal.auditee],["\u7a3d\u6838\u7bc4\u570d",modal.scope],["\u72c0\u614b",modal.status],["\u767c\u73fe\u9805\u6578",modal.findings+"\u9805"],["\u4e0d\u7b26\u5408\u6578",modal.ncCount+"\u9805"]].map(([k,v]) => (<div key={k} style={{ display:"flex", gap:12 }}><div style={{ fontSize:12, color:"#64748b", minWidth:90 }}>{k}</div><div style={{ color:"#e2e8f0", fontWeight:600, fontSize:13 }}>{v}</div></div>))}{modal.status!=="\u5df2\u5b8c\u6210" && (<button onClick={()=>markComplete(modal.id)} style={{ background:"linear-gradient(135deg,#7c3aed,#8b5cf6)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"12px 24px", fontSize:14, fontWeight:700, marginTop:8 }}>\u2713 \u6a19\u8a18\u7a3d\u6838\u5df2\u5b8c\u6210</button>)}</div></Modal>)}')
lines.append('    </div>')
lines.append('  );')
lines.append('}')

content = '\n'.join(lines) + '\n'
with open(r'C:\Users\USER\Desktop\自動稽核程式\audit-dashboard.jsx', 'a', encoding='utf-8-sig') as f:
    f.write(content)
print('Part6 AuditPlanTab OK')
